      "content": "const fs = require('fs');
const path = require('path');

const problemsFilePath = path.resolve(__dirname, '../../data/problems.json');

function loadProblems() {
  const raw = fs.readFileSync(problemsFilePath, 'utf-8');
  return JSON.parse(raw);
}

/**
 * Filters problems by difficulty, tags
 * @param {Array} problems
 * @param {Object} filters
 * @param {string} filters.difficulty
 * @param {Array<string>} filters.tags
 * @returns {Array}
 */
function filterProblems(problems, filters) {
  let filtered = problems;
  if (filters.difficulty) {
    filtered = filtered.filter(p => p.difficulty === filters.difficulty);
  }
  if (filters.tags && filters.tags.length > 0) {
    filtered = filtered.filter(p => {
      if (!p.tags) return false;
      return filters.tags.every(tag => p.tags.includes(tag));
    });
  }
  return filtered;
}

/**
 * Computes totals of problems by language and status
 * @param {Array} problems
 * @returns {{componentLanguageTotals: Object, componentStatusTotals: Object}}
 */
function computeComponentTotals(problems) {
  const componentLanguageTotals = {};
  const componentStatusTotals = {};

  problems.forEach(problem => {
    // Count by language
    if (problem.language) {
      componentLanguageTotals[problem.language] = (componentLanguageTotals[problem.language] || 0) + 1;
    }
    // Count by status
    if (problem.status) {
      componentStatusTotals[problem.status] = (componentStatusTotals[problem.status] || 0) + 1;
    }
  });

  return { componentLanguageTotals, componentStatusTotals };
}

/**
 * List problems with optional filters, pagination, and includeComponents metadata
 * @param {Object} options
 * @param {boolean} options.includeComponents
 * @param {string} [options.difficulty]
 * @param {Array<string>} [options.tags]
 * @param {number} [options.limit]
 * @param {number} [options.offset]
 * @returns {Object} response
 */
function listProblems({ includeComponents = false, difficulty, tags = [], limit = 50, offset = 0 } = {}) {
  const allProblems = loadProblems();

  // Apply filters
  const filteredProblems = filterProblems(allProblems, { difficulty, tags });

  // Apply pagination
  const pagedProblems = filteredProblems.slice(offset, offset + limit);

  const response = {
    problems: pagedProblems
  };

  if (includeComponents) {
    // Compute totals on the filtered + limited set
    const { componentLanguageTotals, componentStatusTotals } = computeComponentTotals(pagedProblems);
    response.metadata = {
      componentLanguageTotals,
      componentStatusTotals
    };
  }

  return response;
}

module.exports = {
  listProblems
};
